`timescale 1ns/1ps

import rv32ec_zmmul_core_pkg::*;

module csr_trap_controller (
  input  logic                             clk,
  input  logic                             rst_n,
  input  logic                             csr_en_i,
  input  logic                             csr_we_i,
  input  logic [RV32EC_ZMMUL_CSR_ADDR_W-1:0] csr_addr_i,
  input  logic [RV32EC_ZMMUL_XLEN-1:0]     csr_wdata_i,
  input  logic                             trap_req_i,
  input  logic [RV32EC_ZMMUL_TRAP_CAUSE_W-1:0] trap_cause_i,
  input  logic [RV32EC_ZMMUL_PC_W-1:0]     trap_pc_i,
  input  logic                             ext_irq_i,
  input  logic                             mret_i,
  output logic [RV32EC_ZMMUL_XLEN-1:0]     csr_rdata_o,
  output logic                             trap_redirect_valid_o,
  output logic [RV32EC_ZMMUL_PC_W-1:0]     trap_redirect_pc_o,
  output logic                             mret_redirect_valid_o,
  output logic [RV32EC_ZMMUL_PC_W-1:0]     mret_redirect_pc_o
);

  localparam logic [11:0] CSR_MSTATUS = 12'h300;
  localparam logic [11:0] CSR_MTVEC   = 12'h305;
  localparam logic [11:0] CSR_MEPC    = 12'h341;
  localparam logic [11:0] CSR_MCAUSE  = 12'h342;

  localparam logic [31:0] MSTATUS_MIE_MASK  = 32'h0000_0008;
  localparam logic [31:0] MSTATUS_MPIE_MASK = 32'h0000_0080;
  localparam logic [31:0] MSTATUS_RESET     = 32'h0000_0008;
  localparam logic [31:0] MCAUSE_MEI        = 32'h8000_000B;

  logic [RV32EC_ZMMUL_XLEN-1:0] mstatus_q;
  logic [RV32EC_ZMMUL_XLEN-1:0] mtvec_q;
  logic [RV32EC_ZMMUL_XLEN-1:0] mepc_q;
  logic [RV32EC_ZMMUL_XLEN-1:0] mcause_q;

  logic mie_enabled;
  logic irq_accept;
  logic trap_accept;

  assign mie_enabled = mstatus_q[3];
  assign irq_accept  = ext_irq_i & mie_enabled;
  assign trap_accept = trap_req_i | irq_accept;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      mstatus_q               <= MSTATUS_RESET;
      mtvec_q                 <= RV32EC_ZMMUL_MTVEC_RESET;
      mepc_q                  <= '0;
      mcause_q                <= '0;
      trap_redirect_valid_o   <= 1'b0;
      trap_redirect_pc_o      <= '0;
      mret_redirect_valid_o   <= 1'b0;
      mret_redirect_pc_o      <= '0;
    end else begin
      trap_redirect_valid_o   <= 1'b0;
      mret_redirect_valid_o   <= 1'b0;
      trap_redirect_pc_o      <= trap_redirect_pc_o;
      mret_redirect_pc_o      <= mret_redirect_pc_o;

      if (trap_accept) begin
        mepc_q                <= {trap_pc_i[31:1], 1'b0};
        mcause_q              <= irq_accept ? MCAUSE_MEI : {{28{1'b0}}, trap_cause_i};
        mstatus_q[7]          <= mstatus_q[3];
        mstatus_q[3]          <= 1'b0;
        trap_redirect_valid_o <= 1'b1;
        trap_redirect_pc_o    <= {mtvec_q[31:2], 2'b00};
      end else if (mret_i) begin
        mstatus_q[3]          <= mstatus_q[7];
        mstatus_q[7]          <= 1'b1;
        mret_redirect_valid_o <= 1'b1;
        mret_redirect_pc_o    <= mepc_q;
      end else if (csr_en_i && csr_we_i) begin
        unique case (csr_addr_i)
          CSR_MSTATUS: begin
            mstatus_q[3] <= csr_wdata_i[3];
            mstatus_q[7] <= csr_wdata_i[7];
          end
          CSR_MTVEC: begin
            mtvec_q <= {csr_wdata_i[31:2], 2'b00};
          end
          CSR_MEPC: begin
            mepc_q <= {csr_wdata_i[31:1], 1'b0};
          end
          CSR_MCAUSE: begin
            mcause_q <= csr_wdata_i;
          end
          default: begin
            // Unsupported CSR writes are ignored.
          end
        endcase
      end
    end
  end

  always_comb begin
    csr_rdata_o = 32'h0000_0000;

    if (csr_en_i) begin
      unique case (csr_addr_i)
        CSR_MSTATUS: csr_rdata_o = mstatus_q;
        CSR_MTVEC:   csr_rdata_o = mtvec_q;
        CSR_MEPC:    csr_rdata_o = mepc_q;
        CSR_MCAUSE:  csr_rdata_o = mcause_q;
        default:     csr_rdata_o = 32'h0000_0000;
      endcase
    end
  end

endmodule
